UPDATE t_student
student_no = #{studentNo}, name = #{name}, class_info = #{classInfo}, department_id = #{departmentId}, advisor_teacher_id = #{advisorTeacherId}, reviewer_teacher_id = #{reviewerTeacherId}, defense_type = #{defenseType}, title = #{title}, summary = #{summary}, defense_group_id = #{defenseGroupId}, defense_year = #{defenseYear},
WHERE id = #{id}

UPDATE t_student
SET defense_group_id = #{groupId}
WHERE id = #{id}

mapper.select:
SELECT s.*, a.id as advisor_id, a.teacher_no as advisor_teacher_no, a.name as advisor_name, a.title as advisor_title, r.id as reviewer_id, r.teacher_no as reviewer_teacher_no, r.name as reviewer_name, r.title as reviewer_title, g.id as group_id, g.name as group_name, d.name as department_name, d.code as department_code FROM t_student s LEFT JOIN teacher a ON s.advisor_teacher_id = a.id LEFT JOIN teacher r ON s.reviewer_teacher_id = r.id LEFT JOIN defense_group g ON s.defense_group_id = g.id LEFT JOIN department d ON s.department_id = d.id
AND (s.student_no LIKE CONCAT('%', #{keyword}, '%') OR s.name LIKE CONCAT('%', #{keyword}, '%') OR s.title LIKE CONCAT('%', #{keyword}, '%'))
AND s.department_id = #{departmentId}
AND s.defense_year = #{year}
ORDER BY s.id DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM t_student s
AND (s.student_no LIKE CONCAT('%', #{keyword}, '%') OR s.name LIKE CONCAT('%', #{keyword}, '%') OR s.title LIKE CONCAT('%', #{keyword}, '%'))
AND s.department_id = #{departmentId}
AND s.defense_year = #{year}
